            'attrs': {'src': '', 'class': ['avatar'], 'alt': '用户头像', 'width': '80', 'height': '80'},
            'description': '头像图片',
            'expected': False
        },
        {
            'url': 'https://substack-post-media.s3.amazonaws.com/public/images/abc123def456.jpg',
            'attrs': {'src': '', 'alt': '神经网络架构图', 'class': ['content-image']},
            'description': '正常文章图片',
            'expected': True
        },
        {
            'url': 'data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP8z8BQDwAEhQGAhKmMIQAAAABJRU5ErkJggg==',
            'attrs': {'src': '', 'alt': ''},
            'description': '数据URI',
            'expected': False
        }
    ]

    results = []
    for test_case in test_cases:
        class MockImgElement:
            def __init__(self, attrs):
                self.attrs = attrs

